SELECT event_time, level, logger_name, message
FROM system.text_log
WHERE event_time > {from:DateTime}
/*[ AND event_time <= {to:DateTime} ]*/
/*[ AND level = {level:Enum8('Fatal' = 1, 'Critical' = 2, 'Error' = 3, 'Warning' = 4, 'Notice' = 5, 'Information' = 6, 'Debug' = 7, 'Trace' = 8, 'Test' = 9)} ]*/
/*[ AND positionCaseInsensitive(logger_name, {logger:String}) > 0 ]*/
/*[ AND positionCaseInsensitive(message, {message:String}) > 0 ]*/
ORDER BY event_time DESC
LIMIT 500
